import { Observable, Subject } from '../src/observable'

let failures = 0
async function check(name: string, got: unknown, want: unknown) {
  got = await got  // resolve promises transparently
  const ok = JSON.stringify(got) === JSON.stringify(want)
  console.log(`  ${ok ? 'PASS' : 'FAIL'} — ${name}`)
  if (!ok) {
    console.log(`       got:  ${JSON.stringify(got)}`)
    console.log(`       want: ${JSON.stringify(want)}`)
    failures++
  }
}

;(async () => {
await check("Observable.of emits values", (() => { const vals: number[] = []; Observable.of(1,2,3).subscribe(v=>vals.push(v)); return vals })(), [1,2,3])
await check("map transforms", (() => { const vals: number[] = []; Observable.of(1,2,3).map(x=>x*2).subscribe(v=>vals.push(v)); return vals })(), [2,4,6])
await check("filter selects", (() => { const vals: number[] = []; Observable.of(1,2,3,4).filter(x=>x%2===0).subscribe(v=>vals.push(v)); return vals })(), [2,4])
await check("unsubscribe stops", (() => { const vals: number[] = []; const s = new Subject<number>(); const sub = s.subscribe(v=>vals.push(v)); s.next(1); sub.unsubscribe(); s.next(2); return vals })(), [1])
await check("Subject emits", (() => { const vals: number[] = []; const s = new Subject<number>(); s.subscribe(v=>vals.push(v)); s.next(1); s.next(2); return vals })(), [1,2])
console.log(failures === 0 ? 'ALL PASS' : `${failures} FAILURE(S)`)
process.exit(failures === 0 ? 0 : 1)
})()
